import { useState, useEffect, useCallback } from 'react'
import { Icon, Skeleton } from '../common'
import { ColorExtractor } from './ColorExtractor'
import { PosterRenderer } from './PosterRenderer'
import { SocialCardBuilder } from './SocialCardBuilder'
import * as api from '../../services/api'

const ASSET_TYPE_LABELS = {
  image: 'AI配图',
  poster: '品牌海报',
  'poster-bg': '海报背景',
  'social-card': '社交图卡',
  color: '色板',
}

const TABS = [
  { id: 'assets', name: '资产管理', icon: 'bookmark' },
  { id: 'extract', name: '色板提取', icon: 'sparkles' },
  { id: 'poster', name: '海报生成', icon: 'printer' },
  { id: 'social', name: '社交图卡', icon: 'share' },
]

function AssetCard({ asset, onDelete, onPreview }) {
  const [deleting, setDeleting] = useState(false)

  const handleDelete = async () => {
    setDeleting(true)
    try {
      await onDelete(asset.id)
    } finally {
      setDeleting(false)
    }
  }

  const handleDownload = () => {
    if (!asset.imageData) return
    const link = document.createElement('a')
    link.download = `${asset.title || asset.id}.png`
    link.href = asset.imageData
    link.click()
  }

  return (
    <div className="asset-card">
      <div className="asset-card-preview" onClick={() => onPreview(asset)}>
        {asset.imageData ? (
          <img src={asset.imageData} alt={asset.title || '品牌资产'} className="asset-card-image" />
        ) : (
          <div className="asset-card-placeholder">
            <Icon name="file" size={24} />
          </div>
        )}
        <div className="asset-card-overlay">
          <Icon name="eye" size={16} />
        </div>
      </div>
      <div className="asset-card-info">
        <div className="asset-card-top">
          <span className="asset-card-type">{ASSET_TYPE_LABELS[asset.assetType] || asset.assetType}</span>
          <span className="asset-card-time">{new Date(asset.createdAt).toLocaleDateString('zh-CN')}</span>
        </div>
        <h4 className="asset-card-title">{asset.title || '未命名资产'}</h4>
        {asset.tags?.length > 0 && (
          <div className="asset-card-tags">
            {asset.tags.slice(0, 3).map((tag, i) => (
              <span key={i} className="asset-card-tag">{tag}</span>
            ))}
          </div>
        )}
      </div>
      <div className="asset-card-actions">
        {asset.imageData && (
          <button className="icon-btn" onClick={handleDownload} title="下载">
            <Icon name="download" size={14} />
          </button>
        )}
        <button className="icon-btn icon-btn--danger" onClick={handleDelete} disabled={deleting} title="删除">
          <Icon name="trash" size={14} />
        </button>
      </div>
    </div>
  )
}

function AssetPreviewModal({ asset, onClose }) {
  if (!asset) return null

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content modal-content--lg" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h3>{asset.title || '资产预览'}</h3>
          <button className="btn btn-ghost btn-xs" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          {asset.imageData && (
            <div className="asset-preview-image-wrap">
              <img src={asset.imageData} alt={asset.title} className="asset-preview-image" />
            </div>
          )}
          <div className="asset-preview-meta">
            <div className="asset-meta-row">
              <span className="asset-meta-label">类型</span>
              <span className="asset-meta-value">{ASSET_TYPE_LABELS[asset.assetType] || asset.assetType}</span>
            </div>
            {asset.prompt && (
              <div className="asset-meta-row">
                <span className="asset-meta-label">提示词</span>
                <span className="asset-meta-value">{asset.prompt}</span>
              </div>
            )}
            {asset.metadata?.model && (
              <div className="asset-meta-row">
                <span className="asset-meta-label">模型</span>
                <span className="asset-meta-value">{asset.metadata.model}</span>
              </div>
            )}
            {asset.metadata?.provider && (
              <div className="asset-meta-row">
                <span className="asset-meta-label">提供商</span>
                <span className="asset-meta-value">{asset.metadata.provider}</span>
              </div>
            )}
            <div className="asset-meta-row">
              <span className="asset-meta-label">创建时间</span>
              <span className="asset-meta-value">{new Date(asset.createdAt).toLocaleString('zh-CN')}</span>
            </div>
          </div>
        </div>
        <div className="modal-footer">
          {asset.imageData && (
            <button className="btn btn-primary btn-sm" onClick={() => {
              const link = document.createElement('a')
              link.download = `${asset.title || asset.id}.png`
              link.href = asset.imageData
              link.click()
            }}>
              <Icon name="download" size={14} /> 下载
            </button>
          )}
          <button className="btn btn-ghost btn-sm" onClick={onClose}>关闭</button>
        </div>
      </div>
    </div>
  )
}

function BrandSelector({ brands, selectedBrand, onSelect, onCreate }) {
  return (
    <div className="brand-selector">
      <label className="poster-control-label">选择品牌</label>
      <div className="brand-selector-row">
        <select
          className="input"
          value={selectedBrand || ''}
          onChange={(e) => onSelect(e.target.value)}
        >
          <option value="">请选择品牌</option>
          {brands.map(b => (
            <option key={b.brandName} value={b.brandName}>{b.brandName}</option>
          ))}
        </select>
        <button className="btn btn-ghost btn-sm" onClick={onCreate}>
          <Icon name="pen" size={14} /> 新建
        </button>
      </div>
    </div>
  )
}

function CreateBrandModal({ onClose, onCreated }) {
  const [brandName, setBrandName] = useState('')
  const [toneKeywords, setToneKeywords] = useState('')
  const [values, setValues] = useState('')
  const [loading, setLoading] = useState(false)

  const handleSubmit = async () => {
    if (!brandName.trim()) return
    setLoading(true)
    try {
      await api.createBrandDNA({
        brandName: brandName.trim(),
        toneKeywords: toneKeywords.split(',').map(s => s.trim()).filter(Boolean),
        values: values.split(',').map(s => s.trim()).filter(Boolean),
      })
      onCreated(brandName.trim())
      onClose()
    } catch (err) {
      console.error('创建品牌失败:', err)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h3>新建品牌</h3>
          <button className="btn btn-ghost btn-xs" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <div className="poster-form-group">
            <label className="poster-control-label">品牌名称 <span className="required">*</span></label>
            <input className="input" value={brandName} onChange={(e) => setBrandName(e.target.value)} placeholder="输入品牌名称" />
          </div>
          <div className="poster-form-group">
            <label className="poster-control-label">品牌调性关键词</label>
            <input className="input" value={toneKeywords} onChange={(e) => setToneKeywords(e.target.value)} placeholder="用逗号分隔，如：专业,温暖,可靠" />
          </div>
          <div className="poster-form-group">
            <label className="poster-control-label">品牌价值观</label>
            <input className="input" value={values} onChange={(e) => setValues(e.target.value)} placeholder="用逗号分隔，如：创新,品质,用户至上" />
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost btn-sm" onClick={onClose}>取消</button>
          <button className="btn btn-primary btn-sm" onClick={handleSubmit} disabled={!brandName.trim() || loading}>
            {loading ? '创建中...' : '创建品牌'}
          </button>
        </div>
      </div>
    </div>
  )
}

export function PageAssets({ onNavigate, showToast }) {
  const [activeTab, setActiveTab] = useState('assets')
  const [brands, setBrands] = useState([])
  const [selectedBrand, setSelectedBrand] = useState('')
  const [assets, setAssets] = useState([])
  const [totalAssets, setTotalAssets] = useState(0)
  const [loading, setLoading] = useState(true)
  const [previewAsset, setPreviewAsset] = useState(null)
  const [showCreateBrand, setShowCreateBrand] = useState(false)
  const [filterType, setFilterType] = useState('')

  const currentBrand = brands.find(b => b.brandName === selectedBrand)

  const loadBrands = useCallback(async () => {
    try {
      const data = await api.getBrands()
      setBrands(data)
      if (data.length > 0 && !selectedBrand) {
        setSelectedBrand(data[0].brandName)
      }
    } catch {}
  }, [selectedBrand])

  const loadAssets = useCallback(async () => {
    if (!selectedBrand) {
      setAssets([])
      setTotalAssets(0)
      setLoading(false)
      return
    }

    setLoading(true)
    try {
      const data = await api.getBrandAssets(selectedBrand, { assetType: filterType || undefined })
      setAssets(data.assets || [])
      setTotalAssets(data.total || 0)
    } catch {
      setAssets([])
    } finally {
      setLoading(false)
    }
  }, [selectedBrand, filterType])

  useEffect(() => {
    loadBrands()
  }, [loadBrands])

  useEffect(() => {
    loadAssets()
  }, [loadAssets])

  const handleDeleteAsset = useCallback(async (id) => {
    try {
      await api.deleteBrandAsset(id)
      setAssets(prev => prev.filter(a => a.id !== id))
      setTotalAssets(prev => prev - 1)
      showToast?.('资产已删除')
    } catch {
      showToast?.('删除失败', 'error')
    }
  }, [showToast])

  const handleColorsExtracted = useCallback((colors) => {
    if (selectedBrand) {
      api.createBrandDNA({
        brandName: selectedBrand,
        colorPalette: colors,
      }).then(() => {
        loadBrands()
        showToast?.('色板已保存到品牌')
      }).catch(() => {})
    }
  }, [selectedBrand, loadBrands, showToast])

  const handleBrandCreated = useCallback((name) => {
    setSelectedBrand(name)
    loadBrands()
    showToast?.('品牌创建成功')
  }, [loadBrands, showToast])

  const handleAssetGenerated = useCallback(() => {
    loadAssets()
    showToast?.('资产已保存')
  }, [loadAssets, showToast])

  return (
    <div className="page page-assets">
      <div className="assets-header">
        <h2 className="assets-title">品牌视觉资产</h2>
        <p className="assets-subtitle">管理品牌色板、海报和社交媒体图卡</p>
      </div>

      <BrandSelector
        brands={brands}
        selectedBrand={selectedBrand}
        onSelect={setSelectedBrand}
        onCreate={() => setShowCreateBrand(true)}
      />

      {currentBrand && (
        <div className="brand-info-bar">
          <div className="brand-info-item">
            <span className="brand-info-label">调性</span>
            <div className="brand-info-tags">
              {currentBrand.toneKeywords?.map((k, i) => (
                <span key={i} className="brand-info-tag">{k}</span>
              )) || <span className="brand-info-empty">未设置</span>}
            </div>
          </div>
          <div className="brand-info-item">
            <span className="brand-info-label">色板</span>
            <div className="brand-color-chips">
              {currentBrand.colorPalette?.length > 0 ? (
                currentBrand.colorPalette.map((c, i) => (
                  <span key={i} className="brand-color-chip" style={{ backgroundColor: c }} title={c} />
                ))
              ) : (
                <span className="brand-info-empty">未提取</span>
              )}
            </div>
          </div>
          <div className="brand-info-item">
            <span className="brand-info-label">资产数</span>
            <span className="brand-info-value">{totalAssets}</span>
          </div>
        </div>
      )}

      <div className="assets-tabs">
        {TABS.map(tab => (
          <button
            key={tab.id}
            className={`assets-tab ${activeTab === tab.id ? 'assets-tab--active' : ''}`}
            onClick={() => setActiveTab(tab.id)}
          >
            <Icon name={tab.icon} size={14} />
            <span>{tab.name}</span>
          </button>
        ))}
      </div>

      <div className="assets-content">
        {activeTab === 'assets' && (
          <div className="assets-list-section">
            <div className="assets-list-header">
              <div className="assets-filter">
                <select className="input input-search" value={filterType} onChange={(e) => setFilterType(e.target.value)}>
                  <option value="">全部类型</option>
                  {Object.entries(ASSET_TYPE_LABELS).map(([key, label]) => (
                    <option key={key} value={key}>{label}</option>
                  ))}
                </select>
              </div>
              <span className="assets-count">共 {totalAssets} 项</span>
            </div>

            {loading ? (
              <div className="assets-loading"><Skeleton count={4} /></div>
            ) : assets.length > 0 ? (
              <div className="assets-grid">
                {assets.map(asset => (
                  <AssetCard
                    key={asset.id}
                    asset={asset}
                    onDelete={handleDeleteAsset}
                    onPreview={setPreviewAsset}
                  />
                ))}
              </div>
            ) : (
              <div className="assets-empty">
                <Icon name="bookmark" size={32} />
                <p>{selectedBrand ? '暂无品牌资产，试试生成海报或图卡' : '请先选择品牌'}</p>
              </div>
            )}
          </div>
        )}

        {activeTab === 'extract' && (
          <ColorExtractor
            brandName={selectedBrand}
            onColorsExtracted={handleColorsExtracted}
          />
        )}

        {activeTab === 'poster' && (
          <PosterRenderer
            brandName={selectedBrand}
            colorPalette={currentBrand?.colorPalette}
            onPosterGenerated={handleAssetGenerated}
          />
        )}

        {activeTab === 'social' && (
          <SocialCardBuilder
            brandName={selectedBrand}
            colorPalette={currentBrand?.colorPalette}
            onCardGenerated={handleAssetGenerated}
          />
        )}
      </div>

      {previewAsset && (
        <AssetPreviewModal
          asset={previewAsset}
          onClose={() => setPreviewAsset(null)}
        />
      )}

      {showCreateBrand && (
        <CreateBrandModal
          onClose={() => setShowCreateBrand(false)}
          onCreated={handleBrandCreated}
        />
      )}
    </div>
  )
}

import { useState, useRef, useCallback, useEffect } from 'react'
import { Icon } from '../common'
import * as api from '../../services/api'

const POSTER_TEMPLATES = [
  {
    id: 'modern-minimal',
    name: '现代简约',
    desc: '简洁大气的品牌海报',
    layout: 'center',
    bgStyle: 'gradient',
    titleSize: 48,
    bodySize: 16,
    padding: 60,
  },
  {
    id: 'editorial',
    name: '杂志编辑',
    desc: '杂志风格的排版设计',
    layout: 'left',
    bgStyle: 'solid',
    titleSize: 42,
    bodySize: 15,
    padding: 80,
  },
  {
    id: 'bold-impact',
    name: '大胆冲击',
    desc: '视觉冲击力强的海报',
    layout: 'center',
    bgStyle: 'dark',
    titleSize: 56,
    bodySize: 18,
    padding: 50,
  },
  {
    id: 'elegant-soft',
    name: '优雅柔和',
    desc: '柔和色调的优雅设计',
    layout: 'center',
    bgStyle: 'soft',
    titleSize: 44,
    bodySize: 15,
    padding: 70,
  },
]

function hexToRgb(hex) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex)
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16),
  } : { r: 27, g: 67, b: 50 }
}

function renderPosterToCanvas(canvas, config) {
  const ctx = canvas.getContext('2d')
  const { width, height, template, title, subtitle, bodyText, brandName, colorPalette, backgroundImage } = config

  canvas.width = width
  canvas.height = height

  const primary = colorPalette?.[0] || '#1B4332'
  const secondary = colorPalette?.[1] || '#2D6A4F'
  const accent = colorPalette?.[2] || '#BC8A3F'
  const primaryRgb = hexToRgb(primary)
  const secondaryRgb = hexToRgb(secondary)

  if (backgroundImage) {
    const img = new Image()
    img.onload = () => {
      ctx.drawImage(img, 0, 0, width, height)
      ctx.fillStyle = `rgba(${primaryRgb.r}, ${primaryRgb.g}, ${primaryRgb.b}, 0.7)`
      ctx.fillRect(0, 0, width, height)
      renderTextContent(ctx, config, primary, accent, width, height)
    }
    img.src = backgroundImage
  } else {
    switch (template.bgStyle) {
      case 'gradient':
        const grad = ctx.createLinearGradient(0, 0, width, height)
        grad.addColorStop(0, primary)
        grad.addColorStop(1, secondary)
        ctx.fillStyle = grad
        ctx.fillRect(0, 0, width, height)
        break
      case 'solid':
        ctx.fillStyle = primary
        ctx.fillRect(0, 0, width, height)
        break
      case 'dark':
        const darkGrad = ctx.createLinearGradient(0, 0, 0, height)
        darkGrad.addColorStop(0, '#0D1117')
        darkGrad.addColorStop(1, `rgba(${primaryRgb.r}, ${primaryRgb.g}, ${primaryRgb.b}, 0.8)`)
        ctx.fillStyle = darkGrad
        ctx.fillRect(0, 0, width, height)
        break
      case 'soft':
        const softGrad = ctx.createRadialGradient(width / 2, height / 2, 0, width / 2, height / 2, Math.max(width, height) * 0.7)
        softGrad.addColorStop(0, `rgba(${primaryRgb.r}, ${primaryRgb.g}, ${primaryRgb.b}, 0.15)`)
        softGrad.addColorStop(1, '#FFFEF9')
        ctx.fillStyle = softGrad
        ctx.fillRect(0, 0, width, height)
        break
      default:
        ctx.fillStyle = primary
        ctx.fillRect(0, 0, width, height)
    }

    renderDecorations(ctx, template, primaryRgb, accent, width, height)
    renderTextContent(ctx, config, primary, accent, width, height)
  }
}

function renderDecorations(ctx, template, primaryRgb, accent, width, height) {
  ctx.save()
  ctx.globalAlpha = 0.08

  switch (template.id) {
    case 'modern-minimal':
      ctx.beginPath()
      ctx.arc(width * 0.8, height * 0.2, 200, 0, Math.PI * 2)
      ctx.fillStyle = '#ffffff'
      ctx.fill()
      ctx.beginPath()
      ctx.arc(width * 0.15, height * 0.85, 120, 0, Math.PI * 2)
      ctx.fill()
      break
    case 'editorial':
      ctx.strokeStyle = '#ffffff'
      ctx.lineWidth = 1
      for (let i = 0; i < 5; i++) {
        ctx.beginPath()
        ctx.moveTo(80 + i * 20, 0)
        ctx.lineTo(80 + i * 20, height)
        ctx.stroke()
      }
      break
    case 'bold-impact':
      ctx.beginPath()
      ctx.arc(width * 0.5, height * 0.5, Math.max(width, height) * 0.4, 0, Math.PI * 2)
      ctx.fillStyle = accent
      ctx.globalAlpha = 0.06
      ctx.fill()
      break
    case 'elegant-soft':
      for (let i = 0; i < 3; i++) {
        ctx.beginPath()
        ctx.arc(width * (0.3 + i * 0.2), height * (0.3 + i * 0.15), 80 + i * 40, 0, Math.PI * 2)
        ctx.fillStyle = `rgba(${primaryRgb.r}, ${primaryRgb.g}, ${primaryRgb.b}, 0.05)`
        ctx.globalAlpha = 0.12
        ctx.fill()
      }
      break
  }

  ctx.restore()
}

function renderTextContent(ctx, config, primary, accent, width, height) {
  const { template, title, subtitle, bodyText, brandName } = config
  const pad = template.padding
  const textColor = template.bgStyle === 'soft' ? primary : '#ffffff'
  const subtextColor = template.bgStyle === 'soft' ? `rgba(${hexToRgb(primary).r}, ${hexToRgb(primary).g}, ${hexToRgb(primary).b}, 0.7)` : 'rgba(255,255,255,0.8)'

  ctx.textBaseline = 'top'

  if (brandName) {
    ctx.font = `600 14px "Source Sans 3", sans-serif`
    ctx.fillStyle = accent
    const brandX = template.layout === 'left' ? pad : width / 2
    ctx.textAlign = template.layout === 'left' ? 'left' : 'center'
    ctx.letterSpacing = '3px'
    ctx.fillText(brandName.toUpperCase(), brandX, pad)
  }

  if (title) {
    const titleY = brandName ? pad + 40 : pad + 20
    ctx.font = `700 ${template.titleSize}px "Playfair Display", Georgia, serif`
    ctx.fillStyle = textColor
    const titleX = template.layout === 'left' ? pad : width / 2
    ctx.textAlign = template.layout === 'left' ? 'left' : 'center'

    const maxWidth = width - pad * 2
    const words = title.split('')
    let line = ''
    let lines = []
    for (const char of words) {
      const testLine = line + char
      if (ctx.measureText(testLine).width > maxWidth) {
        lines.push(line)
        line = char
      } else {
        line = testLine
      }
    }
    lines.push(line)

    lines.forEach((l, i) => {
      ctx.fillText(l, titleX, titleY + i * (template.titleSize + 8))
    })
  }

  if (subtitle) {
    const subtitleY = height * 0.45
    ctx.font = `400 ${template.bodySize + 2}px "Source Sans 3", sans-serif`
    ctx.fillStyle = subtextColor
    const subtitleX = template.layout === 'left' ? pad : width / 2
    ctx.textAlign = template.layout === 'left' ? 'left' : 'center'
    ctx.fillText(subtitle, subtitleX, subtitleY)
  }

  if (bodyText) {
    const bodyY = height * 0.55
    ctx.font = `300 ${template.bodySize}px "Source Sans 3", sans-serif`
    ctx.fillStyle = subtextColor
    const bodyX = template.layout === 'left' ? pad : width / 2
    ctx.textAlign = template.layout === 'left' ? 'left' : 'center'
    const maxBodyWidth = width - pad * 2

    const bodyLines = []
    let currentLine = ''
    for (const char of bodyText) {
      const testLine = currentLine + char
      if (ctx.measureText(testLine).width > maxBodyWidth) {
        bodyLines.push(currentLine)
        currentLine = char
      } else {
        currentLine = testLine
      }
    }
    bodyLines.push(currentLine)

    const maxLines = Math.min(bodyLines.length, 6)
    bodyLines.slice(0, maxLines).forEach((l, i) => {
      ctx.fillText(l, bodyX, bodyY + i * (template.bodySize + 8))
    })
  }

  ctx.strokeStyle = accent
  ctx.lineWidth = 2
  ctx.beginPath()
  const lineY = height - pad - 20
  const lineStartX = template.layout === 'left' ? pad : width / 2 - 30
  const lineEndX = template.layout === 'left' ? pad + 60 : width / 2 + 30
  ctx.moveTo(lineStartX, lineY)
  ctx.lineTo(lineEndX, lineY)
  ctx.stroke()
}

export function PosterRenderer({ brandName, storyContent, colorPalette, onPosterGenerated }) {
  const [selectedTemplate, setSelectedTemplate] = useState(POSTER_TEMPLATES[0])
  const [title, setTitle] = useState('')
  const [subtitle, setSubtitle] = useState('')
  const [bodyText, setBodyText] = useState('')
  const [generating, setGenerating] = useState(false)
  const [backgroundImage, setBackgroundImage] = useState(null)
  const canvasRef = useRef(null)

  useEffect(() => {
    if (storyContent) {
      const story = storyContent.brandStory?.content || ''
      const value = storyContent.productValue?.coreValue || ''
